/**
 * A scorer that achieves real parallel speedup using the anti-diagonal wavefront approach.
 *
 * <p>Processes anti-diagonals sequentially; within each diagonal, cells are computed
 * in parallel using forallChunked which distributes work across available worker threads.
 */
public class UsefulParScoring extends AbstractDnaScoring {

    /**
     * The length of the first sequence.
     */
    private final int xLength;

    /**
     * The length of the second sequence.
     */
    private final int yLength;

    /**
     * The Smith-Waterman scoring matrix.
     */
    private final int[][] s;

